import React, { useState } from 'react';
import './GlobeMap.css';

const regions = [
  { name: 'North America', value: 38, revenue: '$94.2k', color: '#7c6af7', cx: 175, cy: 130 },
  { name: 'Europe', value: 28, revenue: '$69.7k', color: '#22d3ee', cx: 380, cy: 105 },
  { name: 'Asia Pacific', value: 22, revenue: '$54.8k', color: '#f97316', cx: 560, cy: 140 },
  { name: 'Latin America', value: 7, revenue: '$17.4k', color: '#a3e635', cx: 230, cy: 215 },
  { name: 'Africa', value: 5, revenue: '$12.4k', color: '#f472b6', cx: 390, cy: 195 },
];

function getDots() {
  const pts = [];
  const zones = [
    [80,80,280,200,0.35],[330,70,200,120,0.4],[440,60,220,180,0.38],
    [340,160,120,130,0.3],[180,175,100,120,0.28],[550,185,90,70,0.3],
  ];
  zones.forEach(([x,y,w,h,d]) => {
    for (let px = x; px < x+w; px += 12)
      for (let py = y; py < y+h; py += 12)
        if (Math.random() < d) pts.push({ x: px+(Math.random()-0.5)*6, y: py+(Math.random()-0.5)*6 });
  });
  return pts;
}

const dots = getDots();

export default function GlobeMap() {
  const [hovered, setHovered] = useState(null);
  return (
    <div className="card globe-card">
      <div className="card-title">Global Revenue Distribution</div>
      <div className="globe-wrap">
        <svg viewBox="0 0 680 280" className="globe-svg">
          <defs>
            <radialGradient id="bgGrad" cx="50%" cy="40%">
              <stop offset="0%" stopColor="rgba(124,106,247,0.06)" />
              <stop offset="100%" stopColor="transparent" />
            </radialGradient>
          </defs>
          <rect width="680" height="280" fill="url(#bgGrad)" rx="12" />
          {dots.map((d, i) => <circle key={i} cx={d.x} cy={d.y} r={1.2} fill="rgba(255,255,255,0.12)" />)}
          {[60,120,180,240].map(y => <line key={y} x1="20" y1={y} x2="660" y2={y} stroke="rgba(255,255,255,0.04)" strokeWidth="0.5" />)}
          {[100,200,300,400,500,600].map(x => <line key={x} x1={x} y1="20" x2={x} y2="260" stroke="rgba(255,255,255,0.04)" strokeWidth="0.5" />)}
          {regions.map(r => {
            const isHov = hovered === r.name;
            const radius = 16 + r.value * 0.5;
            return (
              <g key={r.name} onMouseEnter={() => setHovered(r.name)} onMouseLeave={() => setHovered(null)} style={{ cursor: 'pointer' }}>
                <circle cx={r.cx} cy={r.cy} r={radius + (isHov ? 4 : 0)} fill={r.color} opacity={isHov ? 0.25 : 0.12} style={{ transition: 'all 0.2s' }} />
                <circle cx={r.cx} cy={r.cy} r={radius * 0.55} fill={r.color} opacity={isHov ? 0.9 : 0.6} style={{ transition: 'all 0.2s' }} />
                {isHov && (
                  <g>
                    <rect x={r.cx - 48} y={r.cy - radius - 46} width={96} height={36} rx={6} fill="#1e1e2e" stroke="rgba(255,255,255,0.1)" strokeWidth={0.5} />
                    <text x={r.cx} y={r.cy - radius - 28} textAnchor="middle" fill="rgba(240,240,245,0.6)" fontSize={9} fontFamily="DM Sans">{r.name}</text>
                    <text x={r.cx} y={r.cy - radius - 16} textAnchor="middle" fill={r.color} fontSize={11} fontFamily="Syne" fontWeight={700}>{r.revenue}</text>
                  </g>
                )}
                <text x={r.cx} y={r.cy + 1} textAnchor="middle" dominantBaseline="middle" fill="rgba(255,255,255,0.9)" fontSize={10} fontFamily="Syne" fontWeight={700}>{r.value}%</text>
              </g>
            );
          })}
        </svg>
      </div>
      <div className="region-legend">
        {regions.map(r => (
          <div key={r.name} className={`region-item ${hovered === r.name ? 'hov' : ''}`} onMouseEnter={() => setHovered(r.name)} onMouseLeave={() => setHovered(null)}>
            <span className="region-dot" style={{ background: r.color }} />
            <span className="region-name">{r.name}</span>
            <span className="region-pct">{r.value}%</span>
          </div>
        ))}
      </div>
    </div>
  );
}
